                        status: quality.status || (collectionHealthFieldRows.value.length ? 'warning' : 'no_data'),
                        evidence: `缺失 ${quality.missing_count || 0} / 异常 ${quality.abnormal_count || 0} / 定义 ${collectionHealthFieldRows.value.length}`,
