                        collection_status: status.collection_status || 'unknown',
                        etl_status: status.etl_status || 'unknown',
                        binding_status: status.binding_status || 'unknown',
                        login_status: status.login_status || 'unknown',
                        freshness: status.freshness || 'unknown',
                        source_count: Number(status.source_count || 0),
