                if (rowIds.some(id => referenceIds.includes(id))) return true;
                const rowName = dualOtaNormalizeMatchText(row.hotelName || row.hotel_name || row.name || row.poiName || row.poi_name || '');
                const referenceName = dualOtaNormalizeMatchText(reference.hotelName || reference.hotel_name || reference.name || reference.poiName || reference.poi_name || '');
                return !!rowName && rowName === referenceName;
