                const level = Number(role?.level || 0);
                if (roleId === 1 || roleName === 'admin' || level === 1) return 'admin';
                if (roleId === 2 || roleName === 'beta_user' || level === 2) return 'beta_user';
                if (roleId === 3 || roleName === 'normal_user' || level >= 3) return 'normal_user';
