            const applyCtripAdsDirectConfig = (config = {}, options = {}) => {
                const form = ctripAdsBrowserCaptureForm.value;
                const fillOnlyEmpty = options.fillOnlyEmpty === true;
                const setField = (field, value) => {
                    const text = value === undefined || value === null ? '' : String(value).trim();
                    if (!text) return false;
                    if (fillOnlyEmpty && String(form[field] || '').trim()) return false;
                    form[field] = text;
                    return true;
                };

                let applied = false;
                const adsUrl = firstDataConfigValue(config.url, config.request_url, config.requestUrl);
                if (isCtripAdsApiUrl(adsUrl)) {
                    applied = setField('url', adsUrl) || applied;
                }
                applied = setField('dateRange', firstDataConfigValue(config.date_range, config.dateRange)) || applied;
                applied = setField('startDate', firstDataConfigValue(config.start_date, config.startDate)) || applied;
                applied = setField('endDate', firstDataConfigValue(config.end_date, config.endDate)) || applied;
                if (form.apiType !== normalizeCtripAdsApiType(form.apiType)) {
                    applied = true;
                }
                form.apiType = normalizeCtripAdsApiType(firstDataConfigValue(config.api_type, config.apiType, form.apiType));
                return applied;
            };

